def sum_of_signed_digits(num):

    num_str = str(num)
    total = 0

    for i, char in enumerate(num_str):
        if i == 0 and char == '-':

            continue
        elif num_str[0] == '-' and i == 1:

            total += -int(char)
        else:

            total += int(char)
    return total

